  1	import * as React from 'react';
  2	import { ODF_MODEL_FLAG } from '@odf/core/features';
  3	import {
  4	  useODFNamespaceSelector,
  5	  useODFSystemFlagsSelector,
  6	} from '@odf/core/redux';
  7	import { useGetClusterDetails } from '@odf/core/redux/utils';
  8	import { getStorageClusterInNs } from '@odf/core/utils';
  9	import {
 10	  ODF_OPERATOR,
 11	  OCS_OPERATOR,
 12	  DEFAULT_INFRASTRUCTURE,
 13	} from '@odf/shared/constants';
 14	import {
 15	  useCustomPrometheusPoll,
 16	  usePrometheusBasePath,
 17	} from '@odf/shared/hooks/custom-prometheus-poll';
 18	import { useK8sGet } from '@odf/shared/hooks/k8s-get-hook';
 19	import { useFetchCsv } from '@odf/shared/hooks/use-fetch-csv';
 20	import {
 21	  InfrastructureModel,
 22	  ClusterServiceVersionModel,
 23	  StorageClusterModel,
 24	} from '@odf/shared/models';
 25	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
 26	import { getName } from '@odf/shared/selectors';
 27	import { InfrastructureKind, StorageClusterKind } from '@odf/shared/types';
 28	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 29	import { getOprVersionFromCSV, referenceForModel } from '@odf/shared/utils';
 30	import { getInfrastructurePlatform } from '@odf/shared/utils';
 31	import { resourcePathFromModel } from '@odf/shared/utils';
 32	import { getMetric } from '@odf/shared/utils';
 33	import {
 34	  useFlag,
 35	  useK8sWatchResource,
 36	} from '@openshift-console/dynamic-plugin-sdk';
 37	import { Link } from 'react-router-dom-v5-compat';
 38	import {
 39	  Card,
 40	  CardBody,
 41	  CardHeader,
 42	  CardTitle,
 43	  DescriptionList,
 44	} from '@patternfly/react-core';
 45	import EncryptionPopover from '../../common/details-card/encryption-popover';
 46	import './details-card.scss';
 47	
 48	const NOOBAA_SYSTEM_NAME_QUERY = 'NooBaa_system_info';
 49	const NOOBAA_DASHBOARD_LINK_QUERY = 'NooBaa_system_links';
 50	
 51	const storageClusterResource = {
 52	  kind: referenceForModel(StorageClusterModel),
 53	  isList: true,
 54	};
 55	
 56	export const ObjectServiceDetailsCard: React.FC<{}> = () => {
 57	  const [infrastructure, infrastructureLoaded, infrastructureError] =
 58	    useK8sGet<InfrastructureKind>(InfrastructureModel, DEFAULT_INFRASTRUCTURE);
 59	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
 60	  const [systemResult, systemLoadError] = useCustomPrometheusPoll({
 61	    query: NOOBAA_SYSTEM_NAME_QUERY,
 62	    endpoint: 'api/v1/query' as any,
 63	    basePath: usePrometheusBasePath(),
 64	  });
 65	  const [dashboardLinkResult, dashboardLinkLoadError] = useCustomPrometheusPoll(
 66	    {
 67	      query: NOOBAA_DASHBOARD_LINK_QUERY,
 68	      endpoint: 'api/v1/query' as any,
 69	      basePath: usePrometheusBasePath(),
 70	    }
 71	  );
 72	
 73	  const { t } = useCustomTranslation();
 74	  const isODF = useFlag(ODF_MODEL_FLAG);
 75	  const [ocsData, ocsLoaded, ocsError] = useK8sWatchResource<
 76	    StorageClusterKind[]
 77	  >(storageClusterResource);
 78	  const systemName = getMetric(systemResult, 'system_name');
 79	  const systemLink = getMetric(dashboardLinkResult, 'dashboard');
 80	
 81	  const infrastructurePlatform = getInfrastructurePlatform(infrastructure);
 82	
 83	  const [csv, csvLoaded, csvLoadError] = useFetchCsv({
 84	    specName: !isODF ? OCS_OPERATOR : ODF_OPERATOR,
 85	    namespace: odfNamespace,
 86	    startPollingInstantly: isNsSafe,
 87	  });
 88	
 89	  const serviceVersion = getOprVersionFromCSV(csv);
 90	
 91	  const serviceName = isODF
 92	    ? t('Data Foundation')
 93	    : t('OpenShift Container Storage');
 94	
 95	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
 96	  const { systemFlags } = useODFSystemFlagsSelector();
 97	  const hasRGW = systemFlags[clusterNs]?.isRGWAvailable;
 98	  const hasMCG = systemFlags[clusterNs]?.isNoobaaAvailable;
 99	
100	  const storageCluster: StorageClusterKind = getStorageClusterInNs(
101	    ocsData,
102	    odfNamespace
103	  );
104	
105	  const servicePath = `${resourcePathFromModel(
106	    ClusterServiceVersionModel,
107	    getName(csv),
108	    odfNamespace
109	  )}`;
110	
111	  return (
112	    <Card>
113	      <CardHeader>
114	        <CardTitle>{t('Details')}</CardTitle>
115	      </CardHeader>
116	      <CardBody>
117	        <DescriptionList>
118	          <DetailItem key="service_name" title={t('Service name')}>
119	            {isNsSafe && csvLoaded && !csvLoadError ? (
120	              <Link to={servicePath}>{serviceName}</Link>
121	            ) : (
122	              serviceName
123	            )}
124	          </DetailItem>
125	          <DetailItem
126	            key="system_name"
127	            title={t('System name')}
128	            isLoading={
129	              !systemResult ||
130	              !dashboardLinkResult ||
131	              !systemName ||
132	              !systemLink
133	            }
134	            error={systemLoadError || dashboardLinkLoadError}
135	          >
136	            {hasMCG && (
137	              <p data-test-id="system-name-mcg">
138	                {t('Multicloud Object Gateway')}
139	              </p>
140	            )}
141	            {hasRGW && (
142	              <p
143	                className="ceph-details-card__rgw-system-name--margin"
144	                data-test-id="system-name-rgw"
145	              >
146	                {t('RADOS Object Gateway')}
147	              </p>
148	            )}
149	          </DetailItem>
150	          <DetailItem
151	            key="provider"
152	            title={t('Provider')}
153	            error={infrastructureError}
154	            isLoading={!infrastructureLoaded}
155	          >
156	            {infrastructurePlatform}
157	          </DetailItem>
158	          <DetailItem
159	            key="version"
160	            title={t('Version')}
161	            isLoading={!csvLoaded}
162	            error={csvLoadError}
163	          >
164	            {serviceVersion}
165	          </DetailItem>
166	          <DetailItem
167	            key="encryption"
168	            title={t('Encryption')}
169	            isLoading={!ocsLoaded}
170	            error={ocsError}
171	          >
172	            <EncryptionPopover
173	              cluster={storageCluster}
174	              isObjectDashboard={true}
175	            />
176	          </DetailItem>
177	        </DescriptionList>
178	      </CardBody>
179	    </Card>
180	  );
181	};
182	
183	export const DetailsCard = ObjectServiceDetailsCard;

